const httpRequest = this.helpers.httpRequest;
const clientId = $('Charger Donnees Client').first().json.id;
const campaign = $('Formater Inputs Campagne').first().json.body.campaign;
const SUPABASE_URL = 'PLACEHOLDER_SUPABASE_URL';
const SUPABASE_KEY = 'PLACEHOLDER_SUPABASE_KEY';
const startDate = new Date(campaign.start_date);
const prevEnd = new Date(startDate);
prevEnd.setDate(prevEnd.getDate() - 1);
const prevStart = new Date(prevEnd);
prevStart.setDate(prevStart.getDate() - 30);
const headers = { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` };
let metrics = [];
try {
  const response = await httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/publication_metrics?select=*,publications!inner(client_id,published_at)&publications.client_id=eq.${clientId}&publications.published_at=gte.${prevStart.toISOString().split('T')[0]}&publications.published_at=lte.${prevEnd.toISOString().split('T')[0]}`,
    headers
  });
  metrics = Array.isArray(response) ? response : [];
} catch (e) {}
if (metrics.length === 0) return [{ json: { _noData: true } }];
return metrics.map(m => ({ json: m }));

const httpRequest = this.helpers.httpRequest;
const clientId = $('Charger Donnees Client').first().json.id;
const SUPABASE_URL = 'PLACEHOLDER_SUPABASE_URL';
const SUPABASE_KEY = 'PLACEHOLDER_SUPABASE_KEY';
const headers = { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` };
let captions = [];
try {
  const response = await httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/content_queue?client_id=eq.${clientId}&status=eq.published&order=created_at.desc&limit=20&select=caption,hashtags,caption_style`,
    headers
  });
  captions = Array.isArray(response) ? response : [];
} catch (e) {}
if (captions.length === 0) return [{ json: { _noData: true } }];
return captions.map(c => ({ json: c }));

const client = $('Charger Donnees Client').first().json;
const brand = $('Charger Plateforme Marque').first().json;
const metricsItems = $('Charger Metriques Precedentes').all();
const campaign = $('Formater Inputs Campagne').first().json.body.campaign;

// Charger strategie client
const strategyData = $('Detecter Periode Active').first().json;
const strategy = strategyData.strategy;
const activePeriod = strategyData.active_period;
const hasStrategy = strategyData._strategy_loaded;

const startDate = new Date(campaign.start_date);
const endDate = new Date(campaign.end_date);
const campaignDays = Math.ceil((endDate - startDate) / (1000 * 60 * 60 * 24)) + 1;
const weeksCount = Math.ceil(campaignDays / 7);
const objectives = campaign.objectives || {};
const postsPerWeek = objectives.posts_per_week || 4;
const storiesPerDay = objectives.stories_per_day || 6;
const postsCount = postsPerWeek * weeksCount;
const storiesCount = storiesPerDay * campaignDays;

let phasesCount;
if (campaignDays <= 10) phasesCount = 2;
else if (campaignDays <= 21) phasesCount = 3;
else if (campaignDays <= 45) phasesCount = 4;
else phasesCount = 5;

const intensityCurve = objectives.intensity_curve || 'flat';

let metricsSummary = 'Premiere campagne \u2014 pas de metriques.';
if (metricsItems.length > 0 && !metricsItems[0].json._noData) {
  const rates = metricsItems.map(m => m.json.engagement_rate).filter(Boolean);
  const avgRate = rates.length > 0 ? (rates.reduce((a, b) => a + b, 0) / rates.length * 100).toFixed(1) : 'N/A';
  metricsSummary = `${metricsItems.length} publications, engagement moyen: ${avgRate}%`;
}

const keyDatesFormatted = (objectives.key_dates || []).map(kd => `- ${kd.date} : ${kd.label}`).join('\n') || 'Aucune.';
const kpisFormatted = (objectives.kpis || []).map(k => `${k.metric}: ${k.target}`).join(', ') || 'Non definis';

const curveInstructions = {
  flat: 'Distribue les posts de maniere uniforme entre les phases.',
  ramp_up: 'Commence doucement et augmente progressivement. Derniere phase = plus de posts.',
  peak_middle: 'Faible volume en debut, pic au milieu, retour modere en fin.',
  front_loaded: 'Volume maximal en premiere phase, puis decroissant.'
};

// Construire bloc strategie si disponible
let strategyBlock = '';
let planningRules = '';
let pillarDistField = '';
let pillarQuality = '';
let pillarThinking = '';

if (hasStrategy) {
  const pillarsXml = (strategy.pillars || []).map(p => {
    const dialXml = p.creative_dial ? '\n      <dial>' + JSON.stringify(p.creative_dial) + '</dial>' : '';
    return '    <pillar name="' + p.name + '" percentage="' + p.percentage + '" posts_month="' + p.posts_per_month + '">\n' +
      '      <function>' + (p.function || '') + '</function>\n' +
      '      <content_types>' + (p.content_types || []).join(', ') + '</content_types>\n' +
      '      <rules>' + (p.rules || []).join(' | ') + '</rules>' + dialXml + '\n' +
      '    </pillar>';
  }).join('\n');

  let calendarXml = '';
  if (strategy.weekly_calendar) {
    calendarXml = Object.entries(strategy.weekly_calendar).map(([day, info]) =>
      '    <day name="' + day + '" pillar="' + info.pillar + '" format="' + info.format + '" />'
    ).join('\n');
  }

  let periodXml = '';
  if (activePeriod) {
    const overridesXml = activePeriod.pillar_overrides
      ? '\n    <pillar_overrides>' + JSON.stringify(activePeriod.pillar_overrides) + '</pillar_overrides>'
      : '';
    periodXml = '\n  <active_period number="' + activePeriod.number + '" name="' + activePeriod.name + '">\n' +
      '    <mission>' + (activePeriod.mission || '') + '</mission>' + overridesXml + '\n' +
      '    <kpis>' + JSON.stringify(activePeriod.kpis || {}) + '</kpis>\n' +
      '  </active_period>';
  }

  strategyBlock = '\n## STRATEGIE INSTAGRAM\n<content_strategy>\n' +
    '  <role>' + (strategy.role_statement || '') + '</role>\n' +
    '  <positioning>' + (strategy.positioning_summary || '') + '</positioning>\n\n' +
    '  <pillars>\n' + pillarsXml + '\n  </pillars>\n\n' +
    '  <weekly_calendar>\n' + calendarXml + '\n  </weekly_calendar>' +
    periodXml + '\n</content_strategy>';

  planningRules = '\n<planning_rules>\n' +
    '1. Tu NE REINVENTES PAS les piliers \u2014 utilise ceux definis dans <pillars>.\n' +
    '2. Respecte la distribution % de chaque pilier (tolerance +-5%).\n' +
    '3. Si la periode active a des pillar_overrides, utilise CES pourcentages a la place des pourcentages par defaut.\n' +
    '4. Respecte le mapping jour \u2192 pilier du <weekly_calendar>.\n' +
    '5. Chaque phase doit inclure un champ "pillar_distribution" avec le % par pilier pour cette phase.\n' +
    '6. Les KPIs de la periode active sont tes objectifs.\n' +
    '</planning_rules>\n';

  pillarDistField = ',\n      "pillar_distribution": { "nom_pilier": "pourcentage" }';
  pillarQuality = '\n- pillar_distribution par phase respecte les % definis (tolerance +-5%)\n- Les piliers sont issus de <pillars> \u2014 aucun pilier invente';
  pillarThinking = '\n7. Distribue les piliers selon les % definis (ou pillar_overrides de la periode active).';
}

const systemPrompt = `<role>
Tu es un stratege de campagne specialise reseaux sociaux (Instagram + Facebook).
Tu concois l'architecture macro d'une campagne : phases temporelles, objectifs par phase, intensite, directives thematiques.
Tu ne generes PAS de posts ni de stories individuels \u2014 uniquement le plan directeur en ${phasesCount} phases.
</role>

<rules>
1. Reponds UNIQUEMENT en JSON valide. Aucun texte, commentaire ou explication avant ou apres le JSON.
2. Genere exactement ${phasesCount} phases coherentes couvrant la totalite de la periode [${campaign.start_date}, ${campaign.end_date}].
3. Les phases doivent etre contigues sans trou ni chevauchement.
4. Courbe d'intensite : "${intensityCurve}". ${curveInstructions[intensityCurve] || curveInstructions.flat}
5. posts_target total des phases = exactement ${postsCount}.
6. stories_per_day adapte a l'intensite de chaque phase (moyenne globale ~${storiesPerDay}/jour).
7. Chaque date cle doit tomber dans une phase avec une directive specifique dans key_date_directives.
8. Transitions fluides : le ton et l'objectif de chaque phase doivent s'enchainer naturellement.
</rules>
${planningRules}
<constraints>
VALEURS AUTORISEES \u2014 toute autre valeur invalide le JSON :
- intensity : "low", "medium", "high" (strictement ces 3 valeurs)
- categories_focus : "produit", "coulisses", "equipe", "engagement", "saisonnier", "educatif", "temoignage", "ambiance"
- Toutes les dates au format YYYY-MM-DD, dans la plage [${campaign.start_date}, ${campaign.end_date}]
- Ne genere JAMAIS de texte avant ou apres le bloc JSON
</constraints>

<output_format>
{
  "strategy_summary": "Resume strategie 2-3 phrases, specifique au client",
  "campaign_phases": [
    {
      "name": "nom evocateur",
      "start_date": "YYYY-MM-DD",
      "end_date": "YYYY-MM-DD",
      "objective": "objectif clair",
      "tone": "ton dominant",
      "intensity": "low|medium|high",
      "themes_priority": ["theme1", "theme2"],
      "categories_focus": ["categorie1", "categorie2"],
      "posts_target": 0,
      "stories_per_day": 0,
      "key_date_directives": [{ "date": "YYYY-MM-DD", "label": "string", "directive": "string" }]${pillarDistField}
    }
  ]
}
</output_format>

<quality_checklist>
Avant de finaliser, verifie :
- Nombre de phases = ${phasesCount}
- Dates couvrent [${campaign.start_date}, ${campaign.end_date}] sans trou
- Somme posts_target = ${postsCount}
- Chaque date cle a une directive
- Intensite suit la courbe "${intensityCurve}"
- categories_focus varient entre les phases
- strategy_summary mentionne le client et son secteur${pillarQuality}
</quality_checklist>`;

const userPrompt = `# BRIEF CAMPAGNE \u2014 ${client.name}

Campagne : ${campaign.name}
Periode : ${campaign.start_date} au ${campaign.end_date} (${campaignDays} jours, ${weeksCount} semaines)
Objectif : ${objectives.primary_goal || 'engagement'} \u2014 ${objectives.description || ''}
KPIs : ${kpisFormatted}
Courbe : ${intensityCurve}
Volume prevu : ${postsCount} posts (${postsPerWeek}/sem) + ${storiesCount} stories (${storiesPerDay}/jour)

### Dates cles
${keyDatesFormatted}

### Themes imposes
${(objectives.themes_imposed || []).join(', ') || 'Aucun'}

### Brief client
${campaign.brief || 'Pas de brief specifique.'}

## MARQUE
Secteur : ${client.industry || '?'}
Mission : ${brand.mission || ''}
Valeurs : ${(brand.brand_values || []).map(v => typeof v === 'object' ? v.name : v).join(', ')}
Personnalite : ${brand.personality || ''}
Ton : ${brand.tone_of_voice || ''}
Audience : ${brand.target_audience || ''}
Essence : ${brand.brand_essence || ''}
Promesse : ${brand.brand_promise || ''}
${strategyBlock}

## METRIQUES RECENTES
${metricsSummary}

<thinking>
Avant de generer le JSON, raisonne etape par etape :
1. Analyse la duree (${campaignDays} jours) et identifie les temps forts naturels.
2. Place les dates cles et determine quelles phases les encadrent.
3. Definis ${phasesCount} phases avec objectifs distincts et transitions logiques.
4. Distribue les ${postsCount} posts selon la courbe "${intensityCurve}".
5. Ajuste stories_per_day par phase (low=moins, high=plus, moyenne ~${storiesPerDay}).
6. Verifie : posts_target total = ${postsCount} exactement.${pillarThinking}
Ne montre PAS ce raisonnement \u2014 genere uniquement le JSON.
</thinking>

Reponds avec le JSON :`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    postsCount,
    storiesCount,
    storiesPerDay,
    campaignDays,
    weeksCount,
    campaignStartDate: campaign.start_date,
    campaignEndDate: campaign.end_date,
    campaignName: campaign.name,
    campaignObjectives: objectives,
    campaignBrief: campaign.brief || '',
    keyDates: objectives.key_dates || [],
    intensityCurve,
    phasesCount,
    _hasStrategy: hasStrategy,
    _strategy: hasStrategy ? strategy : null,
    _activePeriod: activePeriod
  }
}];

const rawOutput = $json.output;
let parsed;
if (typeof rawOutput === 'object' && rawOutput !== null) {
  parsed = rawOutput;
} else {
  try {
    const cleaned = String(rawOutput).replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    parsed = JSON.parse(cleaned);
  } catch (e) {
    throw new Error('Agent Stratege: JSON invalide — ' + e.message);
  }
}

const { strategy_summary, campaign_phases } = parsed;
const meta = $('Construire Prompt Strategie').first().json;
const errors = [];

if (!campaign_phases || campaign_phases.length !== meta.phasesCount) {
  errors.push(`Attendu ${meta.phasesCount} phases, recu ${campaign_phases ? campaign_phases.length : 0}`);
}

if (campaign_phases && campaign_phases.length > 0) {
  const sorted = [...campaign_phases].sort((a, b) => new Date(a.start_date) - new Date(b.start_date));
  if (new Date(sorted[0].start_date) > new Date(meta.campaignStartDate)) errors.push('Trou avant premiere phase');
  if (new Date(sorted[sorted.length - 1].end_date) < new Date(meta.campaignEndDate)) errors.push('Trou apres derniere phase');

  const totalPostsTarget = campaign_phases.reduce((sum, p) => sum + (p.posts_target || 0), 0);
  if (totalPostsTarget !== meta.postsCount) {
    errors.push(`posts_target total ${totalPostsTarget} != attendu ${meta.postsCount}`);
  }

  (meta.keyDates || []).forEach(kd => {
    const inPhase = campaign_phases.some(p => {
      const ps = new Date(p.start_date), pe = new Date(p.end_date), kdd = new Date(kd.date);
      return kdd >= ps && kdd <= pe;
    });
    if (!inPhase) errors.push(`Date cle ${kd.date} hors phases`);
  });
}

if (errors.length > 0) {
  throw new Error('Validation phases echouee:\n' + errors.join('\n'));
}

return [{
  json: {
    strategy_summary,
    campaign_phases,
    ...meta
  }
}];

const meta = $('Valider Phases').first().json;
const brand = $('Charger Plateforme Marque').first().json;
const client = $('Charger Donnees Client').first().json;
const captionsItems = $('Charger Captions Recentes').all();

// Strategie client
const strategyData = $('Detecter Periode Active').first().json;
const strategy = strategyData.strategy;
const hasStrategy = strategyData._strategy_loaded;

const catalogueItems = $('Charger Catalogue Contexte').all();
let catalogueSummary = '';
if (catalogueItems.length > 0 && catalogueItems[0].json && catalogueItems[0].json.name) {
  catalogueSummary = catalogueItems
    .filter(c => c.json.name)
    .map(c => {
      const m = typeof c.json.metadata === 'string' ? JSON.parse(c.json.metadata) : (c.json.metadata || {});
      return '- ' + c.json.name + ': ' + (m.description || '(pas de description)') + ' [' + (m.tags || []).join(', ') + ']';
    })
    .join('\n');
}
const hasContextCatalogue = catalogueSummary.length > 0;

const recentCaptions = captionsItems
  .filter(c => !c.json._noData)
  .map((c, i) => `${i + 1}. [${c.json.caption_style || '?'}] ${(c.json.caption || '').substring(0, 120)}`)
  .join('\n');

const phasesContext = meta.campaign_phases.map(p =>
  `### ${p.name} (${p.start_date} > ${p.end_date}) \u2014 ${p.intensity}\nObjectif : ${p.objective}\nTon : ${p.tone}\nThemes : ${(p.themes_priority || []).join(', ')}\nCategories : ${(p.categories_focus || []).join(', ')}\nPosts a creer : ${p.posts_target}${p.pillar_distribution ? '\nDistribution piliers : ' + JSON.stringify(p.pillar_distribution) : ''}\n${(p.key_date_directives || []).map(kd => `DATE CLE ${kd.date} : ${kd.directive}`).join('\n')}`
).join('\n\n');

const maxStyleCount = Math.ceil(meta.postsCount * 0.25);

// Construire bloc piliers et caption_rules
let pillarContextBlock = '';
let captionRulesBlock = '';
let pillarRule = '';
let pillarOutputField = '';

if (hasStrategy) {
  // Piliers editoriaux
  pillarContextBlock = '## PILIERS EDITORIAUX\n<pillar_definitions>\n' +
    (strategy.pillars || []).map(p => {
      const dialXml = p.creative_dial ? '\n  <creative_dial>' + JSON.stringify(p.creative_dial) + '</creative_dial>' : '';
      return '<pillar_context pillar="' + p.name + '">\n' +
        '  <allowed_content_types>' + (p.content_types || []).join(', ') + '</allowed_content_types>\n' +
        '  <pillar_rules>' + (p.rules || []).join(' | ') + '</pillar_rules>' + dialXml + '\n' +
        '</pillar_context>';
    }).join('\n') + '\n</pillar_definitions>\n';

  // Calendar mapping
  if (strategy.weekly_calendar) {
    pillarContextBlock += '\n<weekly_calendar>\n' +
      Object.entries(strategy.weekly_calendar).map(([day, info]) =>
        '  <day name="' + day + '" pillar="' + info.pillar + '" format="' + info.format + '" />'
      ).join('\n') + '\n</weekly_calendar>\n';
  }

  // Caption rules
  const cr = strategy.caption_rules;
  if (cr) {
    captionRulesBlock = '## REGLES CAPTIONS\n<caption_rules>\n' +
      '  <hook>Premiere ligne = hook visible avant "...voir plus"</hook>\n' +
      (cr.food_length ? '  <length_guide pillar="food">' + cr.food_length + '</length_guide>\n' : '') +
      (cr.education_length ? '  <length_guide pillar="education">' + cr.education_length + '</length_guide>\n' : '') +
      (cr.hashtags_count ? '  <hashtags>' + cr.hashtags_count + ' hashtags, mix : ' + (cr.hashtags_mix || []).join(', ') + '</hashtags>\n' : '') +
      (cr.emoji_usage ? '  <emoji>' + cr.emoji_usage + '</emoji>\n' : '') +
      '</caption_rules>\n';
  }

  pillarRule = '\n9. Assigne un pilier a chaque post. Utilise le <weekly_calendar> pour determiner le pilier du jour, et respecte la pillar_distribution de chaque phase.';
  pillarOutputField = ',\n      "pillar": "nom du pilier (depuis <pillar_definitions>)"';
}

const systemPrompt = `<role>
Tu es un planificateur de contenu feed (posts Instagram + Facebook).
Tu recois un plan de campagne par phases et tu crees les posts detailles pour chaque phase.
Tu excelles dans la variete creative : themes originaux, angles differents, visual_direction riches et evocatrices.
</role>

<rules>
1. Reponds UNIQUEMENT en JSON valide. Aucun texte avant ou apres le JSON.
2. Genere exactement ${meta.postsCount} posts au total.
3. Respecte le nombre de posts par phase (posts_target de chaque phase).
4. Heures de publication : 11:30-13:00 ou 18:00-20:00 uniquement.
5. Chaque date cle DOIT avoir un post avec is_key_date: true.
6. visual_direction doit etre riche et descriptive (lumiere, cadrage, ambiance, elements \u2014 min 15 mots).
7. Pour chaque post, tu PEUX remplir compositing_context (string) ou le laisser null.
   - Remplis-le UNIQUEMENT quand le sujet beneficierait d'une immersion dans un decor reel.
   - Laisse-le null quand la photo doit rester authentique (coulisses, equipe, temoignage).
   - La valeur doit decrire la scene souhaitee en s'appuyant sur le catalogue fourni.
   - Ne force PAS le compositing \u2014 en cas de doute, laisse null.
8. Chaque post DOIT avoir des content_types coherents avec son pilier (si piliers definis).${pillarRule}
</rules>

<constraints>
VALEURS AUTORISEES :
- category : "produit", "coulisses", "equipe", "engagement", "saisonnier", "educatif", "temoignage", "ambiance"
- caption_style : "question_directe", "storytelling_court", "factuel", "exclamatif", "conseil", "citation", "liste", "teaser"
- objective : "engagement", "conversion", "notoriete", "fidelisation"
- sublimation_mode : toujours "creative" pour les posts
- phase : doit correspondre EXACTEMENT a un nom de phase fourni
- Dates : format YYYY-MM-DD, dans la plage de la campagne
- compositing_context : string descriptif ou null

CONTRAINTES DE VARIETE :
- Pas 3 posts consecutifs de la meme categorie.
- Aucun caption_style > 25% du total (max ${maxStyleCount} occurrences).
- Pas 2 posts consecutifs avec le meme angle.
- Pas 3 posts consecutifs avec le meme objectif.
- Les 8 categories doivent etre presentes si campagne >= 2 semaines.
</constraints>

<output_format>
{
  "posts": [
    {
      "scheduled_date": "YYYY-MM-DD",
      "scheduled_time": "HH:MM",
      "phase": "nom exact de la phase",
      "category": "enum",
      "theme": "sujet original et specifique",
      "angle": "approche unique",
      "tone": "ton du post",
      "caption_style": "enum",
      "objective": "enum",
      "visual_direction": "description riche pour le DA (min 15 mots)",
      "sublimation_mode": "creative",
      "cta": "call to action",
      "is_key_date": false,
      "compositing_context": "description scene souhaitee ou null"${pillarOutputField}
    }
  ]
}
</output_format>

<quality_checklist>
Avant de finaliser, verifie :
- Nombre total de posts = ${meta.postsCount}
- Posts par phase respectent posts_target de chaque phase
- Toutes les dates cles ont un post is_key_date: true
- Pas de 3 consecutifs meme categorie
- Aucun caption_style > ${maxStyleCount} occurrences
- Pas de 2 consecutifs meme angle
- Heures dans les creneaux autorises (11:30-13:00 ou 18:00-20:00)
- visual_direction descriptive (pas generique)
- Tous les themes sont uniques ou quasi-uniques
- compositing_context est null OU une description coherente avec le catalogue${hasStrategy ? '\n- Chaque post a un pilier valide issu de <pillar_definitions>' : ''}
</quality_checklist>`;

const compositingSection = hasContextCatalogue
  ? `## PHOTOS DE CONTEXTE DISPONIBLES (COMPOSITING)\n${catalogueSummary}\n\nPour chaque post, tu peux remplir compositing_context pour decrire la scene d'immersion souhaitee.\nExemples : "cuisine \u2014 plan de travail bois, ingredients frais autour du plat", "terrasse \u2014 table en fer forge, lumiere doree fin de journee".\nNe force pas le compositing : laisse null si aucune photo ne correspond ou si l'authenticite prime.`
  : `## COMPOSITING\nAucune photo de contexte disponible \u2014 laisse compositing_context a null pour tous les posts.`;

